blocks.body:
{
    "level": "B1",
    "intro": "У цій темі ти вивчиш <strong>пасивний стан у різних часах<\/strong>: Continuous, Perfect, Future та з модальними дієсловами.",
    "rules": [
        {
            "label": "Continuous",
            "color": "emerald",
            "text": "Тривалі часи: <strong>be + being + V3<\/strong>:",
            "example": "The house is being painted."
        },
        {
            "label": "Perfect",
            "color": "blue",
            "text": "Завершені часи: <strong>have\/had + been + V3<\/strong>:",
            "example": "The letter has been sent."
        },
        {
            "label": "Modals",
            "color": "rose",
            "text": "З модальними: <strong>modal + be + V3<\/strong>:",
            "example": "This must be done today."
        }
    ]
}

{
    "title": "1. Present Continuous Passive",
    "sections": [
        {
            "label": "Структура",
            "color": "emerald",
            "description": "Формула: <strong>am\/is\/are + being + Past Participle (V3)<\/strong>",
            "examples": [
                {
                    "en": "The house is being painted right now.",
                    "ua": "Будинок фарбується прямо зараз."
                },
                {
                    "en": "The documents are being prepared.",
                    "ua": "Документи готуються."
                },
                {
                    "en": "I am being interviewed at the moment.",
                    "ua": "Мене зараз інтерв'юють."
                }
            ]
        },
        {
            "label": "Використання",
            "color": "sky",
            "description": "Дія <strong>відбувається зараз<\/strong>, у процесі.",
            "examples": [
                {
                    "en": "The road is being repaired this week.",
                    "ua": "Дорогу ремонтують цього тижня."
                },
                {
                    "en": "New software is being installed.",
                    "ua": "Нове програмне забезпечення встановлюється."
                }
            ]
        }
    ]
}

{
    "title": "2. Past Continuous Passive",
    "sections": [
        {
            "label": "Структура",
            "color": "emerald",
            "description": "Формула: <strong>was\/were + being + Past Participle (V3)<\/strong>",
            "examples": [
                {
                    "en": "The car was being repaired when I arrived.",
                    "ua": "Машину ремонтували, коли я прийшов."
                },
                {
                    "en": "The rooms were being cleaned all morning.",
                    "ua": "Кімнати прибиралися весь ранок."
                }
            ]
        },
        {
            "label": "Використання",
            "color": "sky",
            "description": "Дія <strong>тривала в минулому<\/strong> в певний момент.",
            "examples": [
                {
                    "en": "While I was waiting, my application was being processed.",
                    "ua": "Поки я чекав, мою заявку обробляли."
                }
            ]
        }
    ]
}

{
    "title": "3. Present Perfect Passive",
    "sections": [
        {
            "label": "Структура",
            "color": "emerald",
            "description": "Формула: <strong>has\/have + been + Past Participle (V3)<\/strong>",
            "examples": [
                {
                    "en": "The project has been completed.",
                    "ua": "Проєкт завершено."
                },
                {
                    "en": "All tickets have been sold.",
                    "ua": "Усі квитки продано."
                },
                {
                    "en": "I have been promoted!",
                    "ua": "Мене підвищили!"
                }
            ]
        },
        {
            "label": "Використання",
            "color": "sky",
            "description": "Дія <strong>завершилась<\/strong>, результат важливий зараз.",
            "examples": [
                {
                    "en": "The report has just been submitted.",
                    "ua": "Звіт щойно подано."
                },
                {
                    "en": "The files have already been deleted.",
                    "ua": "Файли вже видалено."
                }
            ]
        }
    ]
}

{
    "title": "4. Past Perfect Passive",
    "sections": [
        {
            "label": "Структура",
            "color": "emerald",
            "description": "Формула: <strong>had + been + Past Participle (V3)<\/strong>",
            "examples": [
                {
                    "en": "The work had been finished before the deadline.",
                    "ua": "Роботу було закінчено до дедлайну."
                },
                {
                    "en": "The tickets had been sold out before we arrived.",
                    "ua": "Квитки були розпродані до нашого приїзду."
                }
            ]
        },
        {
            "label": "Використання",
            "color": "sky",
            "description": "Дія завершилась <strong>до іншої минулої<\/strong> дії.",
            "examples": [
                {
                    "en": "By the time I got there, the problem had been solved.",
                    "ua": "На момент мого приходу проблему вже вирішили."
                }
            ]
        }
    ]
}

{
    "title": "5. Future Simple Passive",
    "sections": [
        {
            "label": "Структура",
            "color": "emerald",
            "description": "Формула: <strong>will + be + Past Participle (V3)<\/strong>",
            "examples": [
                {
                    "en": "The results will be announced tomorrow.",
                    "ua": "Результати оголосять завтра."
                },
                {
                    "en": "The meeting will be held next Monday.",
                    "ua": "Зустріч відбудеться наступного понеділка."
                },
                {
                    "en": "You will be contacted soon.",
                    "ua": "З вами скоро зв'яжуться."
                }
            ]
        },
        {
            "label": "Заперечення та питання",
            "color": "sky",
            "description": "Заперечення: <strong>will not (won't) + be + V3<\/strong>. Питання: <strong>Will + S + be + V3?<\/strong>",
            "examples": [
                {
                    "en": "The project will not be finished on time.",
                    "ua": "Проєкт не буде завершено вчасно."
                },
                {
                    "en": "Will the report be ready by Friday?",
                    "ua": "Звіт буде готовий до п'ятниці?"
                }
            ]
        }
    ]
}

{
    "title": "6. Passive з модальними дієсловами",
    "sections": [
        {
            "label": "Структура",
            "color": "emerald",
            "description": "Формула: <strong>modal + be + Past Participle (V3)<\/strong>",
            "examples": [
                {
                    "en": "This task must be done today.",
                    "ua": "Це завдання має бути виконане сьогодні."
                },
                {
                    "en": "The rules should be followed.",
                    "ua": "Правила слід дотримуватися."
                },
                {
                    "en": "The document can be downloaded.",
                    "ua": "Документ можна завантажити."
                }
            ]
        },
        {
            "label": "Різні модальні",
            "color": "sky",
            "description": "Працює з усіма модальними: <strong>can, could, may, might, must, should, have to<\/strong>.",
            "examples": [
                {
                    "en": "The work has to be finished.",
                    "ua": "Роботу треба закінчити."
                },
                {
                    "en": "Mistakes might be made.",
                    "ua": "Помилки можуть бути допущені."
                },
                {
                    "en": "This could be improved.",
                    "ua": "Це можна покращити."
                }
            ]
        }
    ]
}

{
    "title": "7. Зведена таблиця часів у пасиві",
    "intro": "Структури пасивного стану в різних часах:",
    "rows": [
        {
            "en": "Present Simple",
            "ua": "am\/is\/are + V3",
            "note": "The letter is written."
        },
        {
            "en": "Past Simple",
            "ua": "was\/were + V3",
            "note": "The letter was written."
        },
        {
            "en": "Present Continuous",
            "ua": "am\/is\/are + being + V3",
            "note": "The letter is being written."
        },
        {
            "en": "Past Continuous",
            "ua": "was\/were + being + V3",
            "note": "The letter was being written."
        },
        {
            "en": "Present Perfect",
            "ua": "has\/have + been + V3",
            "note": "The letter has been written."
        },
        {
            "en": "Past Perfect",
            "ua": "had + been + V3",
            "note": "The letter had been written."
        },
        {
            "en": "Future Simple",
            "ua": "will + be + V3",
            "note": "The letter will be written."
        },
        {
            "en": "Modals",
            "ua": "modal + be + V3",
            "note": "The letter must be written."
        }
    ]
}
